-- ══════════════════════════════════════════════════════════════════════════
-- UNIT 04 — On Condition That
-- Alternatives to 'if'; Expressing Purpose (so as to / in order to)
-- ══════════════════════════════════════════════════════════════════════════

  '{"warmup":"Bạn có thể nói ''You can go... (điều kiện)'' bằng cách nào khác ngoài ''if''? Nghĩ 30 giây.",
    "objectives":["Dùng unless, provided (that), as long as, on condition that, supposing để diễn đạt điều kiện","Phân biệt sắc thái giữa các liên từ điều kiện","Dùng đúng trong văn bản trang trọng và thông thường"],
    "grammarHtml":"<b>Các liên từ điều kiện thay thế ''if'':</b><br><b>unless</b> = if...not / except if: <i>You''ll fail unless you study.</i> (= if you don''t study)<br><b>provided (that) / providing (that)</b> = only if (nhấn mạnh điều kiện bắt buộc): <i>You can borrow it provided you return it.</i><br><b>as long as</b> = miễn là (điều kiện cần duy trì): <i>I''ll support you as long as you''re honest.</i><br><b>on condition that</b> = với điều kiện là (trang trọng): <i>He agreed on condition that he received payment first.</i><br><b>supposing (that) / suppose</b> = giả sử như (điều kiện giả định): <i>Supposing you won the lottery, what would you do?</i><br><b>in case</b> = phòng khi (để chuẩn bị cho khả năng): <i>Take an umbrella in case it rains.</i>",
    "vocabBlock":[
      {"word":"unless","ipa":"/ənˈles/","meaningVi":"trừ phi, nếu không","example":"You won''t succeed unless you try."},
      {"word":"provided that","ipa":"/prəˈvaɪdɪd ðæt/","meaningVi":"với điều kiện là, miễn là","example":"You can leave early provided that you finish your work."},
      {"word":"as long as","ipa":"/æz lɒŋ æz/","meaningVi":"miễn là, chừng nào","example":"I''ll help you as long as you need me."},
      {"word":"on condition that","ipa":"/ɒn kənˈdɪʃn ðæt/","meaningVi":"với điều kiện là","example":"He agreed on condition that he was paid."},
      {"word":"supposing","ipa":"/səˈpəʊzɪŋ/","meaningVi":"giả sử như","example":"Supposing you could fly, where would you go?"},
      {"word":"in case","ipa":"/ɪn keɪs/","meaningVi":"phòng khi, đề phòng","example":"Take your keys in case you come back late."}],
    "examples":[
      {"en":"You can stay unless you cause problems.","vi":"Bạn có thể ở lại trừ phi bạn gây rắc rối."},
      {"en":"I''ll lend you my car provided you drive carefully.","vi":"Tôi sẽ cho bạn mượn xe với điều kiện bạn lái cẩn thận."},
      {"en":"She''ll keep the job as long as the salary is good.","vi":"Cô ấy sẽ giữ công việc miễn là lương tốt."},
      {"en":"He signed the contract on condition that he received a bonus.","vi":"Anh ấy ký hợp đồng với điều kiện được nhận tiền thưởng."}],
    "commonMistakes":["❌ Unless you don''t come → ✅ Unless you come (unless đã có nghĩa phủ định)","in case (phòng khi) ≠ in case of (trong trường hợp có): In case it rains... vs In case of fire, leave the building.","provided/providing + that → both correct."],
    "tips":["unless = if not → không dùng thêm not.","in case nhấn sự chuẩn bị trước; if nhấn điều kiện thực sự."]}'::jsonb);


  '{"warmup":"''Tôi học tiếng Anh để... (mục đích).'' Bạn có thể nói câu này theo bao nhiêu cách khác nhau?",
    "objectives":["Dùng in order to, so as to, so that, for the purpose of để diễn đạt mục đích","Phân biệt cách dùng với to-infinitive đơn giản","Dùng đúng dạng phủ định in order not to / so as not to"],
    "grammarHtml":"<b>Diễn đạt mục đích:</b><br><b>to / in order to / so as to + infinitive:</b> cùng chủ ngữ<br><i>She studied hard to pass the exam.</i> = <i>...in order to pass</i> = <i>...so as to pass</i><br><b>Phủ định:</b> in order not to / so as not to (KHÔNG dùng ''to not'')<br><i>He left early so as not to miss the train.</i><br><b>so that + clause:</b> khác chủ ngữ hoặc nhấn kết quả<br><i>She spoke slowly so that everyone could understand.</i><br><b>for the purpose of + V-ing:</b> trang trọng<br><i>The form is used for the purpose of collecting data.</i><br><b>Thứ tự ưu tiên:</b> to > in order to (trang trọng hơn) > so as to (rất trang trọng) > so that (khi chủ ngữ khác nhau).",
    "vocabBlock":[
      {"word":"in order to","ipa":"/ɪn ˈɔːdə tə/","meaningVi":"để, nhằm","example":"She trained daily in order to run the marathon."},
      {"word":"so as to","ipa":"/səʊ æz tə/","meaningVi":"để, nhằm (trang trọng)","example":"He arrived early so as to get a good seat."},
      {"word":"so that","ipa":"/səʊ ðæt/","meaningVi":"để cho, nhằm mục đích","example":"Speak clearly so that everyone can hear."},
      {"word":"for the purpose of","ipa":"/fɔː ðə ˈpɜːpəs əv/","meaningVi":"nhằm mục đích (trang trọng)","example":"Data is collected for the purpose of research."},
      {"word":"aim","ipa":"/eɪm/","meaningVi":"nhằm, hướng đến","example":"The policy aims to reduce poverty."}],
    "examples":[
      {"en":"He saved money in order to buy a house.","vi":"Anh ấy tiết kiệm tiền để mua nhà."},
      {"en":"She spoke quietly so as not to wake the baby.","vi":"Cô ấy nói nhỏ để không đánh thức em bé."},
      {"en":"We hired a translator so that the clients could understand the presentation.","vi":"Chúng tôi thuê phiên dịch để khách hàng có thể hiểu bài thuyết trình."},
      {"en":"The system was designed for the purpose of improving efficiency.","vi":"Hệ thống được thiết kế nhằm mục đích cải thiện hiệu quả."}],
    "commonMistakes":["❌ so as not study → ✅ so as not to study","❌ in order that she study (cùng chủ ngữ) → ✅ in order to study","❌ for the purpose to + V → ✅ for the purpose of + V-ing"],
    "tips":["Cùng chủ ngữ: dùng in order to / so as to.","Khác chủ ngữ: dùng so that + can/could/would.","Trang trọng: in order to > to."]}'::jsonb);


  '{"warmup":"Trong đàm phán, bạn cần nói ''điều kiện'', ''nhượng bộ'', ''đồng ý có điều kiện''... Bạn biết những từ nào?",
    "objectives":["Học 10 từ vựng B2 về đàm phán và thoả thuận","Dùng từ trong ngữ cảnh điều kiện và mục đích","Phân biệt sắc thái trang trọng/thông thường"],
    "vocabBlock":[
      {"word":"negotiate","ipa":"/nɪˈɡəʊʃieɪt/","meaningVi":"đàm phán, thương lượng","example":"They negotiated a new contract."},
      {"word":"compromise","ipa":"/ˈkɒmprəmaɪz/","meaningVi":"nhượng bộ, thoả hiệp","example":"Both sides had to compromise."},
      {"word":"concession","ipa":"/kənˈseʃn/","meaningVi":"sự nhượng bộ","example":"The company made several concessions."},
      {"word":"stipulate","ipa":"/ˈstɪpjuleɪt/","meaningVi":"quy định, điều kiện hoá","example":"The contract stipulates a three-month notice period."},
      {"word":"clause","ipa":"/klɔːz/","meaningVi":"điều khoản (hợp đồng)","example":"There is a penalty clause in the agreement."},
      {"word":"breach","ipa":"/briːtʃ/","meaningVi":"vi phạm (hợp đồng)","example":"Failing to deliver is a breach of contract."},
      {"word":"comply with","ipa":"/kəmˈplaɪ wɪð/","meaningVi":"tuân thủ, chấp hành","example":"All staff must comply with safety regulations."},
      {"word":"obligation","ipa":"/ˌɒblɪˈɡeɪʃn/","meaningVi":"nghĩa vụ, bổn phận","example":"You have an obligation to inform us."},
      {"word":"mutual","ipa":"/ˈmjuːtʃuəl/","meaningVi":"lẫn nhau, tương hỗ","example":"The agreement is based on mutual trust."},
      {"word":"contingent on","ipa":"/kənˈtɪndʒənt ɒn/","meaningVi":"phụ thuộc vào, tuỳ theo","example":"The deal is contingent on board approval."}],
    "examples":[
      {"en":"The deal was signed on condition that both parties comply with all clauses.","vi":"Hợp đồng được ký với điều kiện cả hai bên tuân thủ tất cả điều khoản."},
      {"en":"She agreed to compromise provided that the salary was negotiated upward.","vi":"Cô ấy đồng ý nhượng bộ với điều kiện lương được thương lượng tăng lên."},
      {"en":"The project is contingent on securing funding by March.","vi":"Dự án phụ thuộc vào việc huy động tài trợ trước tháng Ba."}],
    "commonMistakes":["comply with (đúng) ≠ comply to (sai): you comply WITH regulations.","breach of contract (vi phạm hợp đồng) — breach dùng như danh từ.","contingent on (phụ thuộc vào) ≠ conditioned to."],
    "tips":["negotiate (đàm phán) → negotiation (danh từ) → negotiator (người đàm phán).","stipulate điều kiện trong văn bản pháp lý/hợp đồng."]}'::jsonb);


  '{"warmup":"Đọc cuộc thương lượng hợp đồng và chú ý cách dùng các liên từ điều kiện.",
    "objectives":["Đọc hiểu văn bản B2 về đàm phán","Nhận biết unless/provided/as long as trong ngữ cảnh","Trả lời câu hỏi suy luận"],
    "vocabBlock":[
      {"word":"terms","ipa":"/tɜːmz/","meaningVi":"điều kiện, điều khoản","example":"The terms of the contract were acceptable."},
      {"word":"deal-breaker","ipa":"/ˈdiːl breɪkər/","meaningVi":"điều khoản không thể chấp nhận","example":"The low salary was a deal-breaker for her."},
      {"word":"walk away","ipa":"/wɔːk əˈweɪ/","meaningVi":"bỏ đi, rút lui","example":"They walked away from the deal."},
      {"word":"binding","ipa":"/ˈbaɪndɪŋ/","meaningVi":"có tính ràng buộc","example":"A signed contract is legally binding."}],
    "examples":[
      {"en":"''The salary is acceptable as long as there is a performance bonus,'' said Ana. ''We can offer a bonus,'' replied the director, ''provided that you meet your quarterly targets. However, we cannot proceed unless you sign the non-disclosure agreement first.'' Ana reviewed the terms carefully. The non-disclosure clause was standard — not a deal-breaker. ''I''ll sign,'' she agreed, ''on condition that you increase the holiday allowance to twenty-five days.'' The director paused. ''We can do twenty-three days. In order to finalise the contract today, both parties should be willing to compromise.'' Ana nodded. They shook hands. The agreement was binding from that moment.","vi":"''Mức lương chấp nhận được miễn là có thưởng hiệu suất,'' Ana nói. ''Chúng tôi có thể cung cấp tiền thưởng,'' giám đốc trả lời, ''với điều kiện là bạn đạt chỉ tiêu hàng quý. Tuy nhiên, chúng tôi không thể tiến hành trừ phi bạn ký thỏa thuận bảo mật trước.'' Ana xem xét các điều khoản cẩn thận. Điều khoản bảo mật là tiêu chuẩn — không phải điều không thể chấp nhận. ''Tôi sẽ ký,'' cô đồng ý, ''với điều kiện bạn tăng phép năm lên hai mươi lăm ngày.'' Giám đốc dừng lại. ''Chúng tôi có thể làm hai mươi ba ngày. Để hoàn tất hợp đồng hôm nay, cả hai bên nên sẵn sàng nhượng bộ.'' Ana gật đầu. Họ bắt tay. Thỏa thuận có giá trị ràng buộc từ thời điểm đó."}],
    "commonMistakes":["Đọc kỹ: as long as = điều kiện duy trì; provided that = điều kiện bắt buộc một lần; unless = nếu không."],
    "tips":["Để tìm điều kiện trong văn bản → tìm unless, as long as, provided, on condition that.","deal-breaker = điều không thể thương lượng."]}'::jsonb);


  '{"warmup":"Ôn tập Unit 4: liên từ điều kiện, diễn đạt mục đích và từ vựng đàm phán.","objectives":["Tổng hợp can-do Unit 4","Đạt ≥ 75% để hoàn thành Unit"],"vocabBlock":[],"examples":[],"commonMistakes":[],"tips":["Cần đúng ≥ 8/10 để qua Unit."]}'::jsonb);


