-- ══════════════════════════════════════════════════════════════════════════
-- UNIT 05 — It Is Said That...
-- Passive + Modals; Passive Reporting Structures; Need + Passive
-- ══════════════════════════════════════════════════════════════════════════

  '{"warmup":"''Luật này phải được thực thi.'' / ''Báo cáo có thể đã được gửi.'' — bạn tạo các câu bị động này như thế nào?",
    "objectives":["Tạo câu bị động với modal verbs (must, should, can, might, will...)","Dùng đúng modal + be + V3 (hiện tại) và modal + have been + V3 (quá khứ)","Nhận biết khi nào dùng bị động với modal"],
    "grammarHtml":"<b>Bị động với modal verbs:</b><br><b>Hiện tại/tương lai:</b> modal + be + V3<br><i>must be checked, should be done, can be solved, will be announced</i><br><b>Quá khứ:</b> modal + have been + V3<br><i>must have been stolen, should have been fixed, might have been delayed</i><br><b>Công thức đầy đủ:</b><br>Active: They must test the system. → Passive: The system must be tested.<br>Active: Someone might have taken it. → Passive: It might have been taken.<br><b>Bị động liên tục với modal:</b> modal + be being + V3 (ít gặp)<br><i>The road is being repaired → The road must be being repaired right now.</i><br><b>Các modal thường gặp:</b> must, should, ought to, can, could, may, might, will, would, need to, have to.",
    "vocabBlock":[
      {"word":"be enforced","ipa":"/biː ɪnˈfɔːst/","meaningVi":"được thực thi","example":"The law must be enforced strictly."},
      {"word":"be submitted","ipa":"/biː səbˈmɪtɪd/","meaningVi":"được nộp","example":"All reports must be submitted by Friday."},
      {"word":"be investigated","ipa":"/biː ɪnˈvestɪɡeɪtɪd/","meaningVi":"được điều tra","example":"The matter should be investigated."},
      {"word":"be delayed","ipa":"/biː dɪˈleɪd/","meaningVi":"bị trì hoãn","example":"The flight might be delayed."},
      {"word":"be resolved","ipa":"/biː rɪˈzɒlvd/","meaningVi":"được giải quyết","example":"This issue needs to be resolved."}],
    "examples":[
      {"en":"The results should be announced tomorrow.","vi":"Kết quả nên được thông báo vào ngày mai."},
      {"en":"The documents must have been lost in transit.","vi":"Các tài liệu chắc hẳn đã bị thất lạc trong quá trình vận chuyển."},
      {"en":"This problem can be solved with the right approach.","vi":"Vấn đề này có thể được giải quyết bằng cách tiếp cận đúng."},
      {"en":"Safety regulations must be followed at all times.","vi":"Các quy định an toàn phải được tuân thủ mọi lúc."}],
    "commonMistakes":["❌ must been done → ✅ must be done","❌ should been finished → ✅ should have been finished (quá khứ)","❌ might be being repaired (chỉ dùng trong ngữ cảnh rất đặc biệt)"],
    "tips":["Hiện tại: modal + be + V3.","Quá khứ: modal + have been + V3.","Khi chuyển: active ''they'' / ''someone'' thường bị bỏ trong bị động."]}'::jsonb);


  '{"warmup":"Báo chí thường viết ''Được cho là...'' / ''Được báo cáo là...'' thay vì nói thẳng. Bạn có biết cấu trúc này trong tiếng Anh không?",
    "objectives":["Dùng It is said/reported/believed/thought/known/claimed + that","Dùng Subject + is said/believed/thought to (have) + infinitive","Chuyển đổi giữa hai cấu trúc"],
    "grammarHtml":"<b>Passive Reporting Structures:</b><br><b>Dạng 1 — It + passive + that:</b><br>It is said that he lives in Paris. (người ta nói rằng...)<br>It is believed that the fire started at midnight.<br>It is reported that hundreds are missing.<br><b>Động từ reporting:</b> say, report, believe, think, know, claim, consider, allege, understand<br><b>Dạng 2 — Subject + passive + to-infinitive:</b><br>Cùng thời với mệnh đề chính: He is said to live in Paris.<br>Trước thời điểm mệnh đề chính: He is said to have lived in Paris. (dùng perfect infinitive)<br><b>Chuyển đổi:</b><br>It is believed that she wrote the book. → She is believed to have written the book.<br>It is reported that they are hiding. → They are reported to be hiding.<br><b>Thì quá khứ:</b> It was said / They were reported to...",
    "vocabBlock":[
      {"word":"be alleged","ipa":"/biː əˈledʒd/","meaningVi":"bị cáo buộc","example":"He is alleged to have stolen the money."},
      {"word":"be considered","ipa":"/biː kənˈsɪdəd/","meaningVi":"được coi là","example":"She is considered to be an expert."},
      {"word":"be understood","ipa":"/biː ˌʌndəˈstʊd/","meaningVi":"được hiểu là","example":"It is understood that talks will resume."},
      {"word":"be claimed","ipa":"/biː kleɪmd/","meaningVi":"được cho là, tuyên bố","example":"It is claimed that the drug is safe."}],
    "examples":[
      {"en":"It is said that the ancient temple is over 2,000 years old.","vi":"Người ta nói rằng ngôi đền cổ đại đã hơn 2.000 năm tuổi."},
      {"en":"The suspect is believed to have left the country.","vi":"Nghi phạm được cho là đã rời khỏi đất nước."},
      {"en":"It was reported that the earthquake measured 6.5 on the Richter scale.","vi":"Được báo cáo rằng trận động đất đo 6.5 độ Richter."},
      {"en":"The CEO is said to be considering resignation.","vi":"CEO được cho là đang cân nhắc từ chức."}],
    "commonMistakes":["❌ She is said that she lives in Paris → ✅ She is said to live in Paris (dạng 2 dùng to-infinitive)","Hành động trước → perfect infinitive: is said to HAVE done.","❌ It is said that he has stolen it. → It is said that he stole it. hoặc He is said to have stolen it."],
    "tips":["Dạng 1 (It is...) = trọng tâm thông tin.","Dạng 2 (Subject is...) = trọng tâm đối tượng.","Perfect infinitive (to have done) = hành động đã xảy ra trước thời điểm nói."]}'::jsonb);


  '{"warmup":"Bạn thường đọc tin tức bằng tiếng Anh không? Bạn biết những từ nào liên quan đến báo chí?",
    "objectives":["Học 10 từ vựng B2 về báo chí và truyền thông","Dùng từ trong ngữ cảnh bị động báo cáo","Phân biệt sắc thái từ về nguồn tin và độ chắc chắn"],
    "vocabBlock":[
      {"word":"allege","ipa":"/əˈledʒ/","meaningVi":"cáo buộc, cho là","example":"The newspaper alleged fraud."},
      {"word":"authority","ipa":"/ɔːˈθɒrəti/","meaningVi":"cơ quan thẩm quyền","example":"Authorities are investigating the incident."},
      {"word":"eyewitness","ipa":"/ˈaɪwɪtnəs/","meaningVi":"nhân chứng mắt thấy","example":"An eyewitness said the suspect fled."},
      {"word":"speculation","ipa":"/ˌspekjuˈleɪʃn/","meaningVi":"sự suy đoán, đồn đoán","example":"There is speculation about the resignation."},
      {"word":"statement","ipa":"/ˈsteɪtmənt/","meaningVi":"tuyên bố, phát biểu","example":"The minister issued a statement."},
      {"word":"denial","ipa":"/dɪˈnaɪəl/","meaningVi":"sự phủ nhận","example":"The company issued a denial."},
      {"word":"source","ipa":"/sɔːs/","meaningVi":"nguồn tin","example":"According to our sources, the deal is off."},
      {"word":"coverage","ipa":"/ˈkʌvərɪdʒ/","meaningVi":"sự đưa tin, phạm vi đưa tin","example":"The event received wide coverage."},
      {"word":"breaking news","ipa":"/ˈbreɪkɪŋ njuːz/","meaningVi":"tin tức nóng hổi","example":"Breaking news: a major earthquake has struck."},
      {"word":"reliable","ipa":"/rɪˈlaɪəbl/","meaningVi":"đáng tin cậy","example":"We need a reliable source."}],
    "examples":[
      {"en":"It is alleged that the minister accepted bribes.","vi":"Bị cáo buộc rằng vị bộ trưởng đã nhận hối lộ."},
      {"en":"According to reliable sources, a deal is believed to have been reached.","vi":"Theo các nguồn tin đáng tin cậy, một thỏa thuận được cho là đã đạt được."},
      {"en":"The statement was issued in response to widespread speculation.","vi":"Tuyên bố được đưa ra để đáp lại những đồn đoán lan rộng."}],
    "commonMistakes":["allege (dùng trong báo chí/pháp lý) ≠ say (thông thường): allege nhấn nguồn chưa xác nhận.","coverage (uncountable): wide/extensive/media coverage.","denial ≠ refusal: denial = phủ nhận sự việc; refusal = từ chối làm gì."],
    "tips":["according to sources / it is reported/alleged = báo chí giữ trung lập, chưa xác nhận.","reliable, credible, anonymous sources = mô tả chất lượng nguồn tin."]}'::jsonb);


  '{"warmup":"Đọc một phóng sự báo chí về vụ điều tra — chú ý cách dùng bị động báo cáo và need + passive.",
    "objectives":["Đọc hiểu văn bản báo chí B2","Nhận biết passive reporting structures, passive+modal, need+passive trong ngữ cảnh","Suy luận thái độ của tác giả"],
    "vocabBlock":[
      {"word":"inquiry","ipa":"/ɪnˈkwaɪəri/","meaningVi":"cuộc điều tra","example":"A formal inquiry has been launched."},
      {"word":"misconduct","ipa":"/ˌmɪsˈkɒndʌkt/","meaningVi":"hành vi sai trái","example":"The officer was charged with misconduct."},
      {"word":"transparent","ipa":"/trænsˈpærənt/","meaningVi":"minh bạch","example":"The process must be transparent."},
      {"word":"accountability","ipa":"/əˌkaʊntəˈbɪlɪti/","meaningVi":"trách nhiệm giải trình","example":"There needs to be greater accountability."}],
    "examples":[
      {"en":"THREE senior officials are alleged to have misused public funds, according to a report published yesterday. It is believed that the funds were transferred to private accounts over a period of two years. The matter is being investigated by a special committee and a formal inquiry is expected to be launched next week. An eyewitness is reported to have provided evidence to the authorities. ''Questions need to be asked and answers need to be given,'' said a spokesperson. ''The process must be transparent, and those responsible must be held accountable.'' It is understood that several arrests could be made in the coming days. The authorities have issued a statement, but no further details have been released.","vi":"Ba quan chức cấp cao bị cáo buộc đã lạm dụng công quỹ, theo một báo cáo được công bố hôm qua. Được cho là số tiền đã được chuyển vào tài khoản cá nhân trong hai năm. Vấn đề này đang được một ủy ban đặc biệt điều tra và một cuộc điều tra chính thức dự kiến sẽ được khởi động vào tuần tới. Một nhân chứng được cho là đã cung cấp bằng chứng cho cơ quan chức năng. ''Những câu hỏi cần được đặt ra và câu trả lời cần được đưa ra,'' một người phát ngôn nói. ''Quá trình phải minh bạch, và những người có trách nhiệm phải bị quy trách nhiệm.'' Được hiểu rằng một số vụ bắt giữ có thể xảy ra trong những ngày tới. Chính quyền đã ra tuyên bố, nhưng không có thêm chi tiết nào được công bố."}],
    "commonMistakes":["need to be asked (bị động với need to) = questions need to be asked.","must be held accountable = phải chịu trách nhiệm."],
    "tips":["Báo chí thường dùng alleged, reported, believed để giữ trung lập.","need to be + V3 = cần được (làm gì đó) — bị động với need to."]}'::jsonb);


