INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u04-l1','B2','reading','b2-u04','normal',1,'Alternatives to "if"','unless / provided / as long as / on condition that / supposing',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u04-l1-p1','b2-u04-l1','multiple_choice',1,'practice','easy',false,'{"question":"''You won''t pass ___ you study harder.'' — Điền liên từ phù hợp:","options":[{"id":"a","text":"unless"},{"id":"b","text":"provided"},{"id":"c","text":"in case"}],"correctOptionId":"a","explanationVi":"unless = if...not → unless you study = if you don''t study."}'::jsonb),
 ('b2-u04-l1-p2','b2-u04-l1','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền đúng: ''You can borrow my laptop ___ you return it by Friday.''","acceptedAnswers":["provided","provided that","providing","providing that","as long as"],"explanationVi":"provided that / as long as = điều kiện bắt buộc."}'::jsonb),
 ('b2-u04-l1-p3','b2-u04-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối liên từ với nghĩa:","pairs":[{"left":"unless","right":"trừ phi"},{"left":"as long as","right":"miễn là"},{"left":"in case","right":"phòng khi"},{"left":"supposing","right":"giả sử như"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l1-p4','b2-u04-l1','error_correction',4,'practice','medium',false,'{"question":"Sửa lỗi: ''Unless you don''t bring your passport, you can''t board the plane.''","acceptedAnswers":["Unless you bring your passport, you can''t board the plane.","If you don''t bring your passport, you can''t board the plane."],"explanationVi":"unless đã có nghĩa phủ định → bỏ don''t."}'::jsonb),
 ('b2-u04-l1-p5','b2-u04-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Anh ấy đồng ý ký hợp đồng với điều kiện được tăng lương.","acceptedAnswers":["He agreed to sign the contract on condition that he received a pay rise.","He agreed on condition that his salary was increased."],"explanationVi":"on condition that = với điều kiện là."}'::jsonb),
 ('b2-u04-l1-p6','b2-u04-l1','grammar_fill_blank',6,'practice','medium',false,'{"question":"Điền đúng: ''Take your phone ___ you get lost.''","acceptedAnswers":["in case"],"explanationVi":"in case = phòng khi."}'::jsonb),
 ('b2-u04-l1-p7','b2-u04-l1','multiple_choice',7,'practice','medium',false,'{"question":"Phân biệt: ''unless'' và ''in case'' — câu nào dùng ''in case''?","options":[{"id":"a","text":"You''ll fail ___ you study."},{"id":"b","text":"Take notes ___ you forget."},{"id":"c","text":"I''ll go ___ the weather is good."}],"correctOptionId":"b","explanationVi":"in case = chuẩn bị trước phòng khi xảy ra."}'::jsonb),
 ('b2-u04-l1-q1','b2-u04-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''if...not''?","options":[{"id":"a","text":"provided"},{"id":"b","text":"unless"},{"id":"c","text":"supposing"}],"correctOptionId":"b","explanationVi":"unless = if not."}'::jsonb),
 ('b2-u04-l1-q2','b2-u04-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền đúng: ''___ you could travel anywhere, where would you go?''","acceptedAnswers":["Supposing","Suppose"],"explanationVi":"Supposing = giả sử như (điều kiện giả định)."}'::jsonb),
 ('b2-u04-l1-q3','b2-u04-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chọn câu ĐÚNG (unless không dùng not):","options":[{"id":"a","text":"Unless you don''t hurry, you''ll be late."},{"id":"b","text":"Unless you hurry, you''ll be late."},{"id":"c","text":"Unless you not hurry, you''ll be late."}],"correctOptionId":"b","explanationVi":"unless đã có nghĩa phủ định → chỉ dùng unless + khẳng định."}'::jsonb),
 ('b2-u04-l1-q4','b2-u04-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền đúng (trang trọng): ''She agreed to help ___ she was given credit.''","acceptedAnswers":["on condition that","provided that","providing that"],"explanationVi":"on condition that / provided that = trang trọng."}'::jsonb),
 ('b2-u04-l1-q5','b2-u04-l1','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối cụm từ với nghĩa:","pairs":[{"left":"on condition that","right":"với điều kiện là"},{"left":"in case","right":"phòng khi"},{"left":"as long as","right":"miễn là"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l1-q6','b2-u04-l1','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["provided","finish","the","that","you","go","can","you","work"],"correctOrder":[5,6,0,1,4,2,3,7,8],"explanationVi":"You can go provided that you finish the work."}'::jsonb),
 ('b2-u04-l1-q7','b2-u04-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền đúng: ''I''ll support the project ___ the budget doesn''t exceed $10,000.''","acceptedAnswers":["as long as","provided","provided that","providing","providing that","on condition that"],"explanationVi":"Điều kiện cần duy trì → as long as / provided that."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u04-l2','B2','reading','b2-u04','normal',2,'Expressing Purpose','in order to / so as to / so that / for the purpose of',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u04-l2-p1','b2-u04-l2','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu diễn đạt mục đích ĐÚNG (cùng chủ ngữ, trang trọng):","options":[{"id":"a","text":"She studied so that to pass."},{"id":"b","text":"She studied in order to pass."},{"id":"c","text":"She studied for passing."}],"correctOptionId":"b","explanationVi":"Cùng chủ ngữ + trang trọng → in order to + infinitive."}'::jsonb),
 ('b2-u04-l2-p2','b2-u04-l2','grammar_fill_blank',2,'practice','easy',false,'{"question":"Điền đúng: ''He left early ___ miss the train.'' (phủ định, trang trọng)","acceptedAnswers":["so as not to","in order not to"],"explanationVi":"Phủ định mục đích → so as not to / in order not to."}'::jsonb),
 ('b2-u04-l2-p3','b2-u04-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối cụm từ với nghĩa:","pairs":[{"left":"in order to","right":"để, nhằm"},{"left":"so that","right":"để cho"},{"left":"so as to","right":"để (trang trọng)"},{"left":"for the purpose of","right":"nhằm mục đích (trang trọng)"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l2-p4','b2-u04-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chuyển sang so that: ''They hired a guide ___ (understand) the local culture.''","acceptedAnswers":["so that they could understand","so that the tourists could understand"],"explanationVi":"Khác chủ ngữ → so that + could."}'::jsonb),
 ('b2-u04-l2-p5','b2-u04-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Cô ấy nói chậm để mọi người có thể hiểu.","acceptedAnswers":["She spoke slowly so that everyone could understand.","She spoke slowly so that people could understand."],"explanationVi":"Khác chủ ngữ (she/everyone) → so that + could."}'::jsonb),
 ('b2-u04-l2-p6','b2-u04-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''The app was designed for the purpose to collect user data.''","acceptedAnswers":["The app was designed for the purpose of collecting user data."],"explanationVi":"for the purpose of + V-ing."}'::jsonb),
 ('b2-u04-l2-p7','b2-u04-l2','multiple_choice',7,'practice','medium',false,'{"question":"Khi nào dùng ''so that'' thay vì ''in order to''?","options":[{"id":"a","text":"Khi chủ ngữ hai vế giống nhau"},{"id":"b","text":"Khi chủ ngữ hai vế khác nhau"},{"id":"c","text":"Khi muốn nói trang trọng hơn"}],"correctOptionId":"b","explanationVi":"so that dùng khi chủ ngữ mệnh đề mục đích khác chủ ngữ chính."}'::jsonb),
 ('b2-u04-l2-q1','b2-u04-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG: mục đích (phủ định, trang trọng):","options":[{"id":"a","text":"He whispered to not wake her."},{"id":"b","text":"He whispered in order not to wake her."},{"id":"c","text":"He whispered so as not wake her."}],"correctOptionId":"b","explanationVi":"in order not to + infinitive = mục đích phủ định."}'::jsonb),
 ('b2-u04-l2-q2','b2-u04-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền đúng: ''The notice was posted ___ students know the deadline.''","acceptedAnswers":["so that"],"explanationVi":"Khác chủ ngữ → so that."}'::jsonb),
 ('b2-u04-l2-q3','b2-u04-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Câu nào tương đương: ''She exercised in order to stay healthy.''?","options":[{"id":"a","text":"She exercised so that stay healthy."},{"id":"b","text":"She exercised so as to stay healthy."},{"id":"c","text":"She exercised for to stay healthy."}],"correctOptionId":"b","explanationVi":"in order to = so as to (cùng chủ ngữ)."}'::jsonb),
 ('b2-u04-l2-q4','b2-u04-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Viết lại dùng for the purpose of: ''The survey aims to measure customer satisfaction.''","acceptedAnswers":["The survey is used for the purpose of measuring customer satisfaction.","The survey was conducted for the purpose of measuring customer satisfaction."],"explanationVi":"for the purpose of + V-ing."}'::jsonb),
 ('b2-u04-l2-q5','b2-u04-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối cụm từ với nghĩa:","pairs":[{"left":"so as not to","right":"để không (phủ định)"},{"left":"in order to","right":"để, nhằm"},{"left":"for the purpose of","right":"nhằm mục đích"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l2-q6','b2-u04-l2','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["disturb","so","as","the","not","neighbours","to","He","quietly","spoke"],"correctOrder":[7,9,1,2,4,5,3,6,8,0],"explanationVi":"He spoke quietly so as not to disturb the neighbours."}'::jsonb),
 ('b2-u04-l2-q7','b2-u04-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền đúng: ''The government reduced taxes ___ encourage foreign investment.''","acceptedAnswers":["in order to","so as to","to"],"explanationVi":"Mục đích cùng chủ ngữ → in order to / so as to / to."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u04-l3','B2','reading','b2-u04','normal',3,'Negotiation & Agreement Vocabulary','Từ vựng đàm phán & thương lượng B2',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u04-l3-p1','b2-u04-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"negotiate","right":"đàm phán"},{"left":"compromise","right":"nhượng bộ"},{"left":"clause","right":"điều khoản"},{"left":"breach","right":"vi phạm"}],"explanationVi":"Từ vựng hợp đồng và đàm phán."}'::jsonb),
 ('b2-u04-l3-p2','b2-u04-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"stipulate","right":"quy định"},{"left":"comply with","right":"tuân thủ"},{"left":"obligation","right":"nghĩa vụ"},{"left":"mutual","right":"lẫn nhau"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l3-p3','b2-u04-l3','multiple_choice',3,'practice','easy',false,'{"question":"Điền từ đúng: ''The deal is ___ on board approval.''","options":[{"id":"a","text":"contingent"},{"id":"b","text":"mutual"},{"id":"c","text":"stipulate"}],"correctOptionId":"a","explanationVi":"contingent on = phụ thuộc vào."}'::jsonb),
 ('b2-u04-l3-p4','b2-u04-l3','multiple_choice',4,'practice','medium',false,'{"question":"Điền từ đúng: ''All employees must ___ company health and safety regulations.''","options":[{"id":"a","text":"comply with"},{"id":"b","text":"comply to"},{"id":"c","text":"breach"}],"correctOptionId":"a","explanationVi":"comply WITH (không dùng comply to)."}'::jsonb),
 ('b2-u04-l3-p5','b2-u04-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Hợp đồng quy định một khoảng thời gian thông báo ba tháng.","acceptedAnswers":["The contract stipulates a three-month notice period."],"explanationVi":"stipulate = quy định trong hợp đồng."}'::jsonb),
 ('b2-u04-l3-p6','b2-u04-l3','multiple_choice',6,'practice','medium',false,'{"question":"Từ nào mô tả ''khi một bên không thực hiện điều khoản hợp đồng''?","options":[{"id":"a","text":"concession"},{"id":"b","text":"breach of contract"},{"id":"c","text":"mutual agreement"}],"correctOptionId":"b","explanationVi":"breach of contract = vi phạm hợp đồng."}'::jsonb),
 ('b2-u04-l3-p7','b2-u04-l3','vocabulary_match',7,'practice','easy',false,'{"question":"Nối từ còn lại:","pairs":[{"left":"concession","right":"sự nhượng bộ"},{"left":"contingent on","right":"phụ thuộc vào"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l3-q1','b2-u04-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"negotiate","right":"đàm phán"},{"left":"obligation","right":"nghĩa vụ"},{"left":"clause","right":"điều khoản"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l3-q2','b2-u04-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''sự nhượng bộ''?","options":[{"id":"a","text":"stipulate"},{"id":"b","text":"concession"},{"id":"c","text":"comply"}],"correctOptionId":"b","explanationVi":"concession = nhượng bộ."}'::jsonb),
 ('b2-u04-l3-q3','b2-u04-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền đúng: ''The merger is ___ regulatory approval.''","options":[{"id":"a","text":"contingent on"},{"id":"b","text":"stipulating"},{"id":"c","text":"breaching"}],"correctOptionId":"a","explanationVi":"contingent on = phụ thuộc vào."}'::jsonb),
 ('b2-u04-l3-q4','b2-u04-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền đúng: ''Both sides agreed to ___ so that the deal could proceed.''","acceptedAnswers":["compromise","negotiate"],"explanationVi":"compromise / negotiate = nhượng bộ / đàm phán."}'::jsonb),
 ('b2-u04-l3-q5','b2-u04-l3','multiple_choice',12,'quiz','medium',true,'{"question":"Điền từ đúng: ''The contract ___ that payment must be made within 30 days.''","options":[{"id":"a","text":"stipulates"},{"id":"b","text":"breaches"},{"id":"c","text":"complies"}],"correctOptionId":"a","explanationVi":"stipulate = quy định trong văn bản."}'::jsonb),
 ('b2-u04-l3-q6','b2-u04-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["with","All","comply","must","health","regulations","staff","safety","and"],"correctOrder":[1,5,2,3,4,7,8,6,0],"explanationVi":"All staff must comply with health and safety regulations."}'::jsonb),
 ('b2-u04-l3-q7','b2-u04-l3','vocabulary_match',14,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"mutual","right":"lẫn nhau, tương hỗ"},{"left":"breach","right":"vi phạm"},{"left":"obligation","right":"nghĩa vụ"}],"explanationVi":"Ghép đúng."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u04-l4','B2','reading','b2-u04','normal',4,'A Fair Deal','Đọc hiểu: Thương lượng hợp đồng',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u04-l4-p1','b2-u04-l4','multiple_choice',1,'practice','easy',false,'{"question":"Ana chấp nhận mức lương với điều kiện gì?","options":[{"id":"a","text":"Ký thỏa thuận bảo mật"},{"id":"b","text":"Có thưởng hiệu suất"},{"id":"c","text":"Phép năm 25 ngày"}],"correctOptionId":"b","explanationVi":"''acceptable as long as there is a performance bonus.''"}'::jsonb),
 ('b2-u04-l4-p2','b2-u04-l4','multiple_choice',2,'practice','easy',false,'{"question":"Điều khoản bảo mật (NDA) có phải là deal-breaker với Ana không?","options":[{"id":"a","text":"Có"},{"id":"b","text":"Không, nó là tiêu chuẩn"},{"id":"c","text":"Cô chưa đọc"}],"correctOptionId":"b","explanationVi":"''The non-disclosure clause was standard — not a deal-breaker.''"}'::jsonb),
 ('b2-u04-l4-p3','b2-u04-l4','multiple_choice',3,'practice','medium',false,'{"question":"Công ty không thể tiến hành trừ phi điều gì?","options":[{"id":"a","text":"Ana đồng ý giảm lương"},{"id":"b","text":"Ana ký thỏa thuận bảo mật"},{"id":"c","text":"Ana từ bỏ yêu cầu phép"}],"correctOptionId":"b","explanationVi":"''we cannot proceed unless you sign the non-disclosure agreement first.''"}'::jsonb),
 ('b2-u04-l4-p4','b2-u04-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ trong bài với nghĩa:","pairs":[{"left":"terms","right":"điều kiện, điều khoản"},{"left":"deal-breaker","right":"điều khoản không thể chấp nhận"},{"left":"walk away","right":"bỏ đi, rút lui"},{"left":"binding","right":"có tính ràng buộc"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l4-p5','b2-u04-l4','multiple_choice',5,'practice','medium',false,'{"question":"Liên từ nào trong bài mang nghĩa ''với điều kiện duy trì''?","options":[{"id":"a","text":"unless"},{"id":"b","text":"as long as"},{"id":"c","text":"on condition that"}],"correctOptionId":"b","explanationVi":"as long as = miễn là (điều kiện cần duy trì)."}'::jsonb),
 ('b2-u04-l4-p6','b2-u04-l4','multiple_choice',6,'practice','medium',false,'{"question":"Cuộc đàm phán kết thúc như thế nào?","options":[{"id":"a","text":"Ana bỏ đi không ký"},{"id":"b","text":"Họ nhượng bộ và ký hợp đồng"},{"id":"c","text":"Công ty rút lui"}],"correctOptionId":"b","explanationVi":"''They shook hands. The agreement was binding.''"}'::jsonb),
 ('b2-u04-l4-p7','b2-u04-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành câu của giám đốc: ''We cannot proceed ___ you sign the NDA.''","acceptedAnswers":["unless"],"explanationVi":"unless = if not."}'::jsonb),
 ('b2-u04-l4-q1','b2-u04-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Ana yêu cầu bao nhiêu ngày phép?","options":[{"id":"a","text":"20 ngày"},{"id":"b","text":"23 ngày"},{"id":"c","text":"25 ngày"}],"correctOptionId":"c","explanationVi":"''on condition that you increase the holiday allowance to twenty-five days.''"}'::jsonb),
 ('b2-u04-l4-q2','b2-u04-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Công ty đề xuất bao nhiêu ngày phép cuối cùng?","options":[{"id":"a","text":"25 ngày"},{"id":"b","text":"23 ngày"},{"id":"c","text":"20 ngày"}],"correctOptionId":"b","explanationVi":"''We can do twenty-three days.''"}'::jsonb),
 ('b2-u04-l4-q3','b2-u04-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Liên từ điều kiện nào được dùng để chỉ điều kiện một lần, bắt buộc?","options":[{"id":"a","text":"as long as"},{"id":"b","text":"provided that"},{"id":"c","text":"in case"}],"correctOptionId":"b","explanationVi":"provided that = only if (điều kiện bắt buộc một lần)."}'::jsonb),
 ('b2-u04-l4-q4','b2-u04-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''A signed contract is legally ___.''","acceptedAnswers":["binding"],"explanationVi":"binding = có tính ràng buộc pháp lý."}'::jsonb),
 ('b2-u04-l4-q5','b2-u04-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Từ ''terms'' trong bài có nghĩa là?","options":[{"id":"a","text":"Thời hạn học"},{"id":"b","text":"Điều kiện, điều khoản"},{"id":"c","text":"Vấn đề"}],"correctOptionId":"b","explanationVi":"terms = điều kiện/điều khoản (của hợp đồng)."}'::jsonb),
 ('b2-u04-l4-q6','b2-u04-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"deal-breaker","right":"điều không thể chấp nhận"},{"left":"binding","right":"có tính ràng buộc"},{"left":"walk away","right":"rút lui"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l4-q7','b2-u04-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Điền đúng: ''In order ___ finalise the contract, both parties must compromise.''","acceptedAnswers":["to"],"explanationVi":"in order to + infinitive."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u04-l5','B2','reading','b2-u04','unit_review',5,'Unit 4 Review','Ôn tập Unit 4: Với điều kiện là...',15,35,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u04-l5-q1','b2-u04-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"Điền đúng: ''You won''t get the job ___ you impress the panel.''","acceptedAnswers":["unless"],"explanationVi":"unless = if not."}'::jsonb),
 ('b2-u04-l5-q2','b2-u04-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu diễn đạt mục đích ĐÚNG (cùng chủ ngữ):","options":[{"id":"a","text":"He left early so that catch the train."},{"id":"b","text":"He left early so as to catch the train."},{"id":"c","text":"He left early for catching the train."}],"correctOptionId":"b","explanationVi":"so as to + infinitive = mục đích cùng chủ ngữ."}'::jsonb),
 ('b2-u04-l5-q3','b2-u04-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''vi phạm hợp đồng''?","options":[{"id":"a","text":"concession"},{"id":"b","text":"breach of contract"},{"id":"c","text":"mutual agreement"}],"correctOptionId":"b","explanationVi":"breach of contract = vi phạm."}'::jsonb),
 ('b2-u04-l5-q4','b2-u04-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Điền đúng: ''She reduced her speed ___ not to cause an accident.''","acceptedAnswers":["so as","in order"],"explanationVi":"so as not to / in order not to = mục đích phủ định."}'::jsonb),
 ('b2-u04-l5-q5','b2-u04-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Câu nào SAIУ (lỗi unless)?","options":[{"id":"a","text":"Unless you hurry, you''ll miss the bus."},{"id":"b","text":"Unless you don''t hurry, you''ll miss the bus."},{"id":"c","text":"Unless she calls, I won''t go."}],"correctOptionId":"b","explanationVi":"unless đã có nghĩa phủ định → không thêm don''t."}'::jsonb),
 ('b2-u04-l5-q6','b2-u04-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"stipulate","right":"quy định"},{"left":"comply with","right":"tuân thủ"},{"left":"contingent on","right":"phụ thuộc vào"},{"left":"obligation","right":"nghĩa vụ"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u04-l5-q7','b2-u04-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Điền đúng (khác chủ ngữ): ''The teacher wrote it on the board ___ all students could see.''","acceptedAnswers":["so that"],"explanationVi":"Khác chủ ngữ → so that."}'::jsonb),
 ('b2-u04-l5-q8','b2-u04-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["as","long","stay","you","can","quiet","as","You"],"correctOrder":[7,4,0,1,2,3,5,6],"explanationVi":"You can stay as long as you are quiet."}'::jsonb),
 ('b2-u04-l5-q9','b2-u04-l5','multiple_choice',9,'quiz','medium',true,'{"question":"Liên từ nào phù hợp nhất (trang trọng, nhấn điều kiện):","options":[{"id":"a","text":"if"},{"id":"b","text":"on condition that"},{"id":"c","text":"supposing"}],"correctOptionId":"b","explanationVi":"on condition that = trang trọng, nhấn điều kiện bắt buộc."}'::jsonb),
 ('b2-u04-l5-q10','b2-u04-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Điền đúng (cho the purpose of): ''The survey was conducted ___ measuring customer satisfaction.''","acceptedAnswers":["for the purpose of"],"explanationVi":"for the purpose of + V-ing."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u05-l1','B2','reading','b2-u05','normal',1,'Passive with Modal Verbs','Modal + be + V3 và tất cả các thì bị động',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u05-l1-p1','b2-u05-l1','multiple_choice',1,'practice','easy',false,'{"question":"Chuyển sang bị động: ''They must check the system.'' →","options":[{"id":"a","text":"The system must checked."},{"id":"b","text":"The system must be checked."},{"id":"c","text":"The system must have been checked."}],"correctOptionId":"b","explanationVi":"Hiện tại: must + be + V3 → must be checked."}'::jsonb),
 ('b2-u05-l1-p2','b2-u05-l1','grammar_fill_blank',2,'practice','easy',false,'{"question":"Chuyển sang bị động: ''Someone might have taken my wallet.''","acceptedAnswers":["My wallet might have been taken."],"explanationVi":"Quá khứ bị động: might + have been + V3."}'::jsonb),
 ('b2-u05-l1-p3','b2-u05-l1','vocabulary_match',3,'practice','easy',false,'{"question":"Nối cụm bị động với nghĩa:","pairs":[{"left":"be enforced","right":"được thực thi"},{"left":"be submitted","right":"được nộp"},{"left":"be delayed","right":"bị trì hoãn"},{"left":"be resolved","right":"được giải quyết"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l1-p4','b2-u05-l1','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chia động từ: ''The report should ___ (submit) by Monday.''","acceptedAnswers":["be submitted"],"explanationVi":"Hiện tại bị động với modal: should be submitted."}'::jsonb),
 ('b2-u05-l1-p5','b2-u05-l1','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Vấn đề an toàn này cần được điều tra ngay lập tức.","acceptedAnswers":["This safety issue needs to be investigated immediately.","The safety issue should be investigated immediately.","This safety problem must be investigated immediately."],"explanationVi":"need to be investigated / should be investigated."}'::jsonb),
 ('b2-u05-l1-p6','b2-u05-l1','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''The documents must been delivered by courier.''","acceptedAnswers":["The documents must be delivered by courier."],"explanationVi":"Hiện tại bị động: must be delivered (không phải must been)."}'::jsonb),
 ('b2-u05-l1-p7','b2-u05-l1','multiple_choice',7,'practice','medium',false,'{"question":"Chuyển sang bị động quá khứ: ''They should have fixed the problem.'' →","options":[{"id":"a","text":"The problem should be fixed."},{"id":"b","text":"The problem should have been fixed."},{"id":"c","text":"The problem should have fixed."}],"correctOptionId":"b","explanationVi":"Quá khứ bị động: should have been fixed."}'::jsonb),
 ('b2-u05-l1-q1','b2-u05-l1','multiple_choice',8,'quiz','easy',true,'{"question":"Công thức bị động HIỆN TẠI với modal:","options":[{"id":"a","text":"modal + have been + V3"},{"id":"b","text":"modal + be + V3"},{"id":"c","text":"modal + been + V3"}],"correctOptionId":"b","explanationVi":"Hiện tại: modal + be + V3."}'::jsonb),
 ('b2-u05-l1-q2','b2-u05-l1','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Chia động từ: ''Safety regulations must ___ (follow) at all times.''","acceptedAnswers":["be followed"],"explanationVi":"must be followed = bị động hiện tại."}'::jsonb),
 ('b2-u05-l1-q3','b2-u05-l1','multiple_choice',10,'quiz','medium',true,'{"question":"Chuyển sang bị động: ''Hackers might have stolen the data.'' →","options":[{"id":"a","text":"The data might be stolen."},{"id":"b","text":"The data might have been stolen."},{"id":"c","text":"The data might have stolen."}],"correctOptionId":"b","explanationVi":"Quá khứ bị động: might have been stolen."}'::jsonb),
 ('b2-u05-l1-q4','b2-u05-l1','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chia động từ: ''This mistake could ___ (avoid) with better planning.''","acceptedAnswers":["have been avoided"],"explanationVi":"Quá khứ bị động: could have been avoided."}'::jsonb),
 ('b2-u05-l1-q5','b2-u05-l1','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối cụm bị động với nghĩa:","pairs":[{"left":"be investigated","right":"được điều tra"},{"left":"be enforced","right":"được thực thi"},{"left":"be resolved","right":"được giải quyết"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l1-q6','b2-u05-l1','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["announced","be","will","results","The","tomorrow"],"correctOrder":[4,0,2,1,3,5],"explanationVi":"The results will be announced tomorrow."}'::jsonb),
 ('b2-u05-l1-q7','b2-u05-l1','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chia động từ: ''The package should ___ (deliver) last week but it hasn''t arrived.''","acceptedAnswers":["have been delivered"],"explanationVi":"Kỳ vọng trong quá khứ nhưng không xảy ra: should have been delivered."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u05-l2','B2','reading','b2-u05','normal',2,'Passive Reporting Structures','It is said / reported / believed + that — He is thought to have...',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u05-l2-p1','b2-u05-l2','multiple_choice',1,'practice','easy',false,'{"question":"Chọn câu ĐÚNG (dạng 2 — Subject + passive):","options":[{"id":"a","text":"He is said that lives in London."},{"id":"b","text":"He is said to live in London."},{"id":"c","text":"He is said living in London."}],"correctOptionId":"b","explanationVi":"Dạng 2: Subject + is said + to-infinitive."}'::jsonb),
 ('b2-u05-l2-p2','b2-u05-l2','grammar_fill_blank',2,'practice','easy',false,'{"question":"Chuyển sang dạng 2: ''It is believed that she has written the report.'' →","acceptedAnswers":["She is believed to have written the report."],"explanationVi":"Hành động đã xảy ra trước → is believed to have written."}'::jsonb),
 ('b2-u05-l2-p3','b2-u05-l2','vocabulary_match',3,'practice','easy',false,'{"question":"Nối cụm bị động báo cáo với nghĩa:","pairs":[{"left":"be alleged","right":"bị cáo buộc"},{"left":"be considered","right":"được coi là"},{"left":"be understood","right":"được hiểu là"},{"left":"be claimed","right":"được tuyên bố là"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l2-p4','b2-u05-l2','grammar_fill_blank',4,'practice','medium',false,'{"question":"Chuyển sang dạng 1: ''Scientists believe that the comet is approaching Earth.'' →","acceptedAnswers":["It is believed that the comet is approaching Earth."],"explanationVi":"It is believed that + clause."}'::jsonb),
 ('b2-u05-l2-p5','b2-u05-l2','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Nghi phạm được cho là đã rời khỏi đất nước vào đêm qua.","acceptedAnswers":["The suspect is said to have left the country last night.","The suspect is believed to have left the country last night."],"explanationVi":"is said/believed to have left (perfect infinitive = hành động đã xảy ra)."}'::jsonb),
 ('b2-u05-l2-p6','b2-u05-l2','error_correction',6,'practice','medium',false,'{"question":"Sửa lỗi: ''The CEO is said that she is considering resignation.''","acceptedAnswers":["The CEO is said to be considering resignation."],"explanationVi":"Dạng 2: is said to be (+ V-ing cho ongoing action)."}'::jsonb),
 ('b2-u05-l2-p7','b2-u05-l2','multiple_choice',7,'practice','medium',false,'{"question":"Khi nào dùng perfect infinitive (to have done) trong dạng 2?","options":[{"id":"a","text":"Khi hành động xảy ra sau thời điểm nói"},{"id":"b","text":"Khi hành động đã xảy ra trước thời điểm nói"},{"id":"c","text":"Luôn luôn"}],"correctOptionId":"b","explanationVi":"Perfect infinitive = hành động đã xảy ra trước thời điểm mệnh đề chính."}'::jsonb),
 ('b2-u05-l2-q1','b2-u05-l2','multiple_choice',8,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (hành động đã xảy ra):","options":[{"id":"a","text":"She is believed to steal the jewels."},{"id":"b","text":"She is believed to have stolen the jewels."},{"id":"c","text":"She is believed stealing the jewels."}],"correctOptionId":"b","explanationVi":"Hành động đã xảy ra → is believed to HAVE stolen."}'::jsonb),
 ('b2-u05-l2-q2','b2-u05-l2','grammar_fill_blank',9,'quiz','easy',true,'{"question":"Điền dạng 1: ''___ reported that several buildings collapsed.''","acceptedAnswers":["It is","It was"],"explanationVi":"It is/was reported that..."}'::jsonb),
 ('b2-u05-l2-q3','b2-u05-l2','multiple_choice',10,'quiz','medium',true,'{"question":"Chuyển đổi: ''It is said that he escaped from prison.'' →","options":[{"id":"a","text":"He is said to escape from prison."},{"id":"b","text":"He is said to have escaped from prison."},{"id":"c","text":"He is said that escaped from prison."}],"correctOptionId":"b","explanationVi":"Đã xảy ra trước → to have escaped."}'::jsonb),
 ('b2-u05-l2-q4','b2-u05-l2','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Chuyển sang dạng 2: ''It is claimed that the drug has no side effects.'' →","acceptedAnswers":["The drug is claimed to have no side effects.","The drug is claimed not to have side effects."],"explanationVi":"is claimed to have no side effects."}'::jsonb),
 ('b2-u05-l2-q5','b2-u05-l2','vocabulary_match',12,'quiz','medium',true,'{"question":"Nối động từ reporting với nghĩa:","pairs":[{"left":"be alleged","right":"bị cáo buộc"},{"left":"be considered","right":"được coi là"},{"left":"be claimed","right":"được tuyên bố là"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l2-q6','b2-u05-l2','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["the","is","to","have","escaped","suspect","believed","country","the"],"correctOrder":[5,1,2,3,4,6,7,8,0],"explanationVi":"The suspect is believed to have escaped the country."}'::jsonb),
 ('b2-u05-l2-q7','b2-u05-l2','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Chuyển sang dạng 1: ''Experts think that the situation is improving.'' →","acceptedAnswers":["It is thought that the situation is improving."],"explanationVi":"It is thought that + clause."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u05-l3','B2','reading','b2-u05','normal',3,'News & Media Vocabulary','Từ vựng báo chí & truyền thông B2',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u05-l3-p1','b2-u05-l3','vocabulary_match',1,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"allege","right":"cáo buộc"},{"left":"eyewitness","right":"nhân chứng mắt thấy"},{"left":"source","right":"nguồn tin"},{"left":"coverage","right":"sự đưa tin"}],"explanationVi":"Từ vựng báo chí."}'::jsonb),
 ('b2-u05-l3-p2','b2-u05-l3','vocabulary_match',2,'practice','easy',false,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"statement","right":"tuyên bố"},{"left":"denial","right":"sự phủ nhận"},{"left":"speculation","right":"đồn đoán"},{"left":"reliable","right":"đáng tin cậy"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l3-p3','b2-u05-l3','multiple_choice',3,'practice','easy',false,'{"question":"Điền từ đúng: ''___ news: the prime minister has announced an early election.''","options":[{"id":"a","text":"Breaking"},{"id":"b","text":"Wide"},{"id":"c","text":"Reliable"}],"correctOptionId":"a","explanationVi":"Breaking news = tin tức nóng hổi."}'::jsonb),
 ('b2-u05-l3-p4','b2-u05-l3','multiple_choice',4,'practice','medium',false,'{"question":"Từ nào khác biệt về nghĩa: ''The company issued a ___ saying the reports were false.''","options":[{"id":"a","text":"denial"},{"id":"b","text":"statement"},{"id":"c","text":"source"}],"correctOptionId":"b","explanationVi":"issue a statement = đưa ra tuyên bố (phát biểu chính thức)."}'::jsonb),
 ('b2-u05-l3-p5','b2-u05-l3','translation',5,'practice','medium',false,'{"question":"Dịch sang tiếng Anh:","sourceText":"Bị cáo buộc rằng vị giám đốc đã thao túng dữ liệu tài chính.","acceptedAnswers":["It is alleged that the director manipulated financial data.","The director is alleged to have manipulated financial data."],"explanationVi":"It is alleged that / is alleged to have done."}'::jsonb),
 ('b2-u05-l3-p6','b2-u05-l3','multiple_choice',6,'practice','medium',false,'{"question":"Điền từ đúng: ''There is a lot of ___ about who will be the next leader.''","options":[{"id":"a","text":"speculation"},{"id":"b","text":"denial"},{"id":"c","text":"coverage"}],"correctOptionId":"a","explanationVi":"speculation = đồn đoán."}'::jsonb),
 ('b2-u05-l3-p7','b2-u05-l3','vocabulary_match',7,'practice','easy',false,'{"question":"Nối từ còn lại:","pairs":[{"left":"authority","right":"cơ quan thẩm quyền"},{"left":"breaking news","right":"tin tức nóng hổi"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l3-q1','b2-u05-l3','vocabulary_match',8,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"allege","right":"cáo buộc"},{"left":"reliable","right":"đáng tin cậy"},{"left":"source","right":"nguồn tin"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l3-q2','b2-u05-l3','multiple_choice',9,'quiz','easy',true,'{"question":"Từ nào mô tả khi một công ty phủ nhận cáo buộc?","options":[{"id":"a","text":"statement"},{"id":"b","text":"denial"},{"id":"c","text":"coverage"}],"correctOptionId":"b","explanationVi":"denial = sự phủ nhận."}'::jsonb),
 ('b2-u05-l3-q3','b2-u05-l3','multiple_choice',10,'quiz','medium',true,'{"question":"Điền từ đúng: ''An ___ reported seeing the suspect near the scene.''","options":[{"id":"a","text":"authority"},{"id":"b","text":"eyewitness"},{"id":"c","text":"allege"}],"correctOptionId":"b","explanationVi":"eyewitness = nhân chứng mắt thấy."}'::jsonb),
 ('b2-u05-l3-q4','b2-u05-l3','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Điền từ đúng: ''The scandal received ___ media ___ around the world.''","acceptedAnswers":["wide coverage","extensive coverage","widespread coverage"],"explanationVi":"wide/extensive coverage = đưa tin rộng rãi."}'::jsonb),
 ('b2-u05-l3-q5','b2-u05-l3','multiple_choice',12,'quiz','medium',true,'{"question":"Sắc thái nào phù hợp khi nguồn tin chưa xác nhận?","options":[{"id":"a","text":"It is confirmed that"},{"id":"b","text":"It is alleged / reported that"},{"id":"c","text":"It is obvious that"}],"correctOptionId":"b","explanationVi":"alleged/reported = chưa chính thức xác nhận."}'::jsonb),
 ('b2-u05-l3-q6','b2-u05-l3','sentence_ordering',13,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["sources","reliable","deal","a","to","According","been","is","have","reached","believed"],"correctOrder":[5,0,1,8,3,7,2,9,6,10,4],"explanationVi":"According to reliable sources, a deal is believed to have been reached."}'::jsonb),
 ('b2-u05-l3-q7','b2-u05-l3','vocabulary_match',14,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"speculation","right":"đồn đoán"},{"left":"authority","right":"cơ quan thẩm quyền"},{"left":"statement","right":"tuyên bố"}],"explanationVi":"Ghép đúng."}'::jsonb);
INSERT INTO learning_lessons (id, level_code, skill_code, unit_id, lesson_type, lesson_order, title, subtitle, duration_minutes, xp_reward, required_score_to_pass, content, theory_content) VALUES
 ('b2-u05-l4','B2','reading','b2-u05','normal',4,'The Investigation','Đọc hiểu: Phóng sự điều tra',12,25,70,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u05-l4-p1','b2-u05-l4','multiple_choice',1,'practice','easy',false,'{"question":"Theo bài, các quan chức bị cáo buộc điều gì?","options":[{"id":"a","text":"Lạm dụng công quỹ"},{"id":"b","text":"Nhận hối lộ từ công ty"},{"id":"c","text":"Tiết lộ thông tin mật"}],"correctOptionId":"a","explanationVi":"''alleged to have misused public funds.''"}'::jsonb),
 ('b2-u05-l4-p2','b2-u05-l4','multiple_choice',2,'practice','easy',false,'{"question":"Ai cung cấp bằng chứng?","options":[{"id":"a","text":"Ủy ban đặc biệt"},{"id":"b","text":"Một nhân chứng"},{"id":"c","text":"Người phát ngôn"}],"correctOptionId":"b","explanationVi":"''An eyewitness is reported to have provided evidence.''"}'::jsonb),
 ('b2-u05-l4-p3','b2-u05-l4','multiple_choice',3,'practice','medium',false,'{"question":"Cấu trúc nào xuất hiện trong: ''Questions need to be asked''?","options":[{"id":"a","text":"Passive reporting"},{"id":"b","text":"Modal + be + V3"},{"id":"c","text":"Need + passive (need to be + V3)"}],"correctOptionId":"c","explanationVi":"need to be asked = need + passive."}'::jsonb),
 ('b2-u05-l4-p4','b2-u05-l4','vocabulary_match',4,'practice','easy',false,'{"question":"Nối từ trong bài với nghĩa:","pairs":[{"left":"inquiry","right":"cuộc điều tra"},{"left":"misconduct","right":"hành vi sai trái"},{"left":"transparent","right":"minh bạch"},{"left":"accountability","right":"trách nhiệm giải trình"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l4-p5','b2-u05-l4','multiple_choice',5,'practice','medium',false,'{"question":"Câu ''It is understood that several arrests could be made'' thuộc cấu trúc gì?","options":[{"id":"a","text":"Active reporting"},{"id":"b","text":"Passive reporting (dạng 1)"},{"id":"c","text":"Modal + be + V3"}],"correctOptionId":"b","explanationVi":"It is understood that + clause = dạng 1 passive reporting."}'::jsonb),
 ('b2-u05-l4-p6','b2-u05-l4','multiple_choice',6,'practice','medium',false,'{"question":"Theo bài, điều gì dự kiến xảy ra vào tuần tới?","options":[{"id":"a","text":"Bắt giữ thủ phạm"},{"id":"b","text":"Khởi động cuộc điều tra chính thức"},{"id":"c","text":"Công bố báo cáo cuối cùng"}],"correctOptionId":"b","explanationVi":"''a formal inquiry is expected to be launched next week.''"}'::jsonb),
 ('b2-u05-l4-p7','b2-u05-l4','grammar_fill_blank',7,'practice','medium',false,'{"question":"Hoàn thành theo bài: ''Those responsible must ___ (hold) accountable.''","acceptedAnswers":["be held"],"explanationVi":"must be held = bị động với modal."}'::jsonb),
 ('b2-u05-l4-q1','b2-u05-l4','multiple_choice',8,'quiz','easy',true,'{"question":"Tiền bị chuyển vào đâu?","options":[{"id":"a","text":"Tài khoản nước ngoài"},{"id":"b","text":"Tài khoản cá nhân"},{"id":"c","text":"Quỹ từ thiện"}],"correctOptionId":"b","explanationVi":"''transferred to private accounts.''"}'::jsonb),
 ('b2-u05-l4-q2','b2-u05-l4','multiple_choice',9,'quiz','easy',true,'{"question":"Người phát ngôn nhấn mạnh điều gì phải có?","options":[{"id":"a","text":"Bằng chứng trực tiếp"},{"id":"b","text":"Sự minh bạch và trách nhiệm giải trình"},{"id":"c","text":"Bồi thường cho nạn nhân"}],"correctOptionId":"b","explanationVi":"''The process must be transparent... those responsible must be held accountable.''"}'::jsonb),
 ('b2-u05-l4-q3','b2-u05-l4','multiple_choice',10,'quiz','medium',true,'{"question":"Từ ''alleged'' trong bài có nghĩa:","options":[{"id":"a","text":"Đã được xác nhận"},{"id":"b","text":"Được cáo buộc (chưa xác nhận)"},{"id":"c","text":"Bị phủ nhận"}],"correctOptionId":"b","explanationVi":"alleged = bị cáo buộc nhưng chưa chứng minh."}'::jsonb),
 ('b2-u05-l4-q4','b2-u05-l4','grammar_fill_blank',11,'quiz','medium',true,'{"question":"Hoàn thành: ''Several arrests ___ (could/make) in coming days.''","acceptedAnswers":["could be made"],"explanationVi":"Modal bị động: could be made."}'::jsonb),
 ('b2-u05-l4-q5','b2-u05-l4','multiple_choice',12,'quiz','medium',true,'{"question":"Cấu trúc ''An eyewitness is reported to have provided evidence'' — loại nào?","options":[{"id":"a","text":"Dạng 1: It is reported that"},{"id":"b","text":"Dạng 2: Subject + is reported to have"},{"id":"c","text":"Need + passive"}],"correctOptionId":"b","explanationVi":"Subject + is reported to have + V3 = dạng 2 passive reporting."}'::jsonb),
 ('b2-u05-l4-q6','b2-u05-l4','vocabulary_match',13,'quiz','easy',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"inquiry","right":"cuộc điều tra"},{"left":"accountability","right":"trách nhiệm giải trình"},{"left":"transparent","right":"minh bạch"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l4-q7','b2-u05-l4','grammar_fill_blank',14,'quiz','hard',true,'{"question":"Hoàn thành passive reporting: ''___ that the officials misused funds.'' (dạng 1)","acceptedAnswers":["It is alleged","It is believed","It is reported","It has been alleged","It has been reported"],"explanationVi":"It is alleged/believed/reported + that."}'::jsonb);
