 ('b2-u05-l5','B2','reading','b2-u05','unit_review',5,'Unit 5 Review','Ôn tập Unit 5: Người ta nói rằng...',15,35,75,'{}'::jsonb,
INSERT INTO learning_lesson_activities (id, lesson_id, activity_type, display_order, phase, difficulty, counts_toward_mastery, payload) VALUES
 ('b2-u05-l5-q1','b2-u05-l5','grammar_fill_blank',1,'quiz','easy',true,'{"question":"Chia động từ: ''The report must ___ (submit) before the deadline.''","acceptedAnswers":["be submitted"],"explanationVi":"must be submitted = bị động hiện tại với modal."}'::jsonb),
 ('b2-u05-l5-q2','b2-u05-l5','multiple_choice',2,'quiz','easy',true,'{"question":"Chọn câu ĐÚNG (passive reporting dạng 2):","options":[{"id":"a","text":"She is believed that she escaped."},{"id":"b","text":"She is believed to have escaped."},{"id":"c","text":"She believed to escape."}],"correctOptionId":"b","explanationVi":"Dạng 2: is believed to have + V3."}'::jsonb),
 ('b2-u05-l5-q3','b2-u05-l5','multiple_choice',3,'quiz','easy',true,'{"question":"Từ nào có nghĩa là ''nhân chứng mắt thấy''?","options":[{"id":"a","text":"source"},{"id":"b","text":"authority"},{"id":"c","text":"eyewitness"}],"correctOptionId":"c","explanationVi":"eyewitness = nhân chứng trực tiếp."}'::jsonb),
 ('b2-u05-l5-q4','b2-u05-l5','grammar_fill_blank',4,'quiz','medium',true,'{"question":"Chuyển sang dạng 1: ''Scientists believe the drug is effective.'' →","acceptedAnswers":["It is believed that the drug is effective."],"explanationVi":"It is believed that + clause."}'::jsonb),
 ('b2-u05-l5-q5','b2-u05-l5','multiple_choice',5,'quiz','medium',true,'{"question":"Chọn câu ĐÚNG (bị động quá khứ với modal):","options":[{"id":"a","text":"The package should been delivered."},{"id":"b","text":"The package should have been delivered."},{"id":"c","text":"The package should be delivered yesterday."}],"correctOptionId":"b","explanationVi":"Quá khứ bị động: should have been delivered."}'::jsonb),
 ('b2-u05-l5-q6','b2-u05-l5','vocabulary_match',6,'quiz','medium',true,'{"question":"Nối từ với nghĩa:","pairs":[{"left":"allege","right":"cáo buộc"},{"left":"speculation","right":"đồn đoán"},{"left":"denial","right":"sự phủ nhận"},{"left":"transparent","right":"minh bạch"}],"explanationVi":"Ghép đúng."}'::jsonb),
 ('b2-u05-l5-q7','b2-u05-l5','grammar_fill_blank',7,'quiz','medium',true,'{"question":"Điền đúng: ''___ reported that several people are missing.''","acceptedAnswers":["It is","It was"],"explanationVi":"It is/was reported that..."}'::jsonb),
 ('b2-u05-l5-q8','b2-u05-l5','sentence_ordering',8,'quiz','hard',true,'{"question":"Sắp xếp thành câu đúng:","tokens":["stolen","might","data","The","have","been"],"correctOrder":[3,0,1,2,4,5],"explanationVi":"The data might have been stolen."}'::jsonb),
 ('b2-u05-l5-q9','b2-u05-l5','multiple_choice',9,'quiz','medium',true,'{"question":"''Questions need to be asked.'' — Cấu trúc này là gì?","options":[{"id":"a","text":"Modal + be + V3"},{"id":"b","text":"Need + passive (need to be + V3)"},{"id":"c","text":"Passive reporting"}],"correctOptionId":"b","explanationVi":"need to be + V3 = need + passive."}'::jsonb),
 ('b2-u05-l5-q10','b2-u05-l5','grammar_fill_blank',10,'quiz','hard',true,'{"question":"Chuyển sang dạng 2: ''It is said that he left the company.'' →","acceptedAnswers":["He is said to have left the company."],"explanationVi":"is said to have left (perfect infinitive = hành động đã xảy ra)."}'::jsonb);
